# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import sys
import argparse
from kafka import KafkaAdminClient
from kafka.admin import NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import TopicAlreadyExistsError, UnknownError

def create_topics(admin_client, topics_config):
    for topic_config in topics_config:
        try:
            topic_name = topic_config['name']
            num_partitions = topic_config.get('partitions', 1)
            replication_factor = topic_config.get('replication_factor', 1)
            topic_configs = topic_config.get('configs', {})
            
            topic = NewTopic(
                name=topic_name,
                num_partitions=num_partitions,
                replication_factor=replication_factor,
                topic_configs=topic_configs
            )
            
            admin_client.create_topics([topic], validate_only=False)
            print(f"Created topic: {topic_name}")
            
        except TopicAlreadyExistsError:
            print(f"Topic {topic_name} already exists")
        except Exception as e:
            print(f"Error creating topic {topic_name}: {e}")

def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("Topics:")
        for topic in topics:
            print(f"  {topic}")
    except Exception as e:
        print(f"Error listing topics: {e}")

def describe_topic(admin_client, topic_name):
    try:
        topic_configs = admin_client.describe_configs([
            ConfigResource(ConfigResourceType.TOPIC, topic_name)
        ])
        print(f"Configs for topic {topic_name}:")
        for config_resource, config in topic_configs.items():
            for key, value in config.items():
                print(f"  {key}: {value}")
    except Exception as e:
        print(f"Error describing topic {topic_name}: {e}")

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers')
    parser.add_argument('--action', required=True, choices=['create', 'list', 'describe'], help='Action to perform')
    parser.add_argument('--topics', nargs='*', help='Topic names for create or describe actions')
    parser.add_argument('--partitions', type=int, help='Number of partitions for topic creation')
    parser.add_argument('--replication-factor', type=int, help='Replication factor for topic creation')
    parser.add_argument('--config', nargs='*', help='Topic configurations in key=value format')
    parser.add_argument('--topic-name', help='Topic name for describe action')
    
    args = parser.parse_args()
    
    admin_client = KafkaAdminClient(
        bootstrap_servers=args.bootstrap_servers
    )
    
    if args.action == 'create':
        topics_config = []
        for topic_name in args.topics:
            topic_config = {
                'name': topic_name,
                'partitions': args.partitions,
                'replication_factor': args.replication_factor,
                'configs': {}
            }
            if args.config:
                for conf in args.config:
                    key, value = conf.split('=')
                    topic_config['configs'][key] = value
            topics_config.append(topic_config)
        create_topics(admin_client, topics_config)
        
    elif args.action == 'list':
        list_topics(admin_client)
        
    elif args.action == 'describe':
        if args.topic_name:
            describe_topic(admin_client, args.topic_name)
        else:
            print("Topic name required for describe action")

if __name__ == '__main__':
    main()